// Smoke-test item for the @gic registry install pipeline. Deliberately has no
// npm or registry dependencies (not even `cn`) so it can install and render
// on any Tailwind consumer, independent of whether @gic/ui-base is present.
export function HelloBadge({ className = "" }: { className?: string }) {
  return (
    <span
      className={`inline-flex items-center gap-1.5 rounded-full border border-neutral-200 bg-white px-2.5 py-0.5 text-xs font-medium uppercase tracking-wide text-neutral-900 dark:border-neutral-800 dark:bg-neutral-950 dark:text-neutral-100 ${className}`.trim()}
    >
      <span aria-hidden="true" className="inline-block h-1.5 w-1.5 rounded-full bg-emerald-500" />
      GIC
    </span>
  );
}
